<template>
	<view class="container">
		<view class="address" v-for="item in list" :key="item.id">
			<view class="address-info" >
				<view class="address-info-top">
					<text class="tag" v-if="item.tag">{{item.tag}}</text>
					<text class="name">{{item.name}}</text>
					<text class="phone">{{item.phone}}</text>
				</view>
				<view class="address-info-bottom">
					{{item.address}}
				</view>
			</view>
			<view class="address-actions">
				<text class="action-default" v-if="!item.isDefault" @click.stop="setDefaultAddress(item)">и®ҫдёәй»ҳи®Ө</text>
				<text class="action-default active" v-else>й»ҳи®Өең°еқҖ</text>
				<text class="action-edit" @click.stop="edit(item)">зј–иҫ‘</text>
				<text class="action-delete" @click.stop="deleteAddress(item)">еҲ йҷӨ</text>
			</view>
		</view>
		<view class="btn">
			<button @click="add()">ж·»еҠ ж–°ең°еқҖ</button>
		</view>
	</view>
</template>

<script>
	import api from '../../utils/http.js'

	export default {
		data() {
			return {
				list: []
			}
		},
		onShow() {
			this.fetchAddressList();
		},
		methods: {
			async fetchAddressList() {
				const token = uni.getStorageSync('Token') || '';
				if (!token) {
					this.list = [];
					return;
				}

				try {
					const res = await api.createRequest({
						url: '/house/address/my',
						method: 'get',
						token
					}, {});

					const sourceList = Array.isArray(res?.data) ? res.data : [];
					this.list = sourceList.map((item, idx) => {
						const fullAddress = [item.province, item.city, item.district, item.detailAddress]
							.filter(Boolean)
							.join('');
						return {
							id: item.id || idx + 1,
							name: item.consignee || item.name || '',
							phone: item.phone || '',
							address: fullAddress || item.address || '',
							province: item.province || 'еӣӣе·қзңҒ',
							city: item.city || 'еҚ—е……еёӮ',
							district: item.district || '',
							detailAddress: item.detailAddress || '',
							isDefault: Number(item.isDefault) === 1 ? 1 : 0,
							createTime: item.createTime || '',
							tag: Number(item.isDefault) === 1 ? 'й»ҳи®Ө' : ''
						};
					});
				} catch (error) {
					console.error('иҺ·еҸ–ең°еқҖеҲ—иЎЁеӨұиҙҘпјҡ', error);
					this.$utils.toastTip('иҺ·еҸ–ең°еқҖеҲ—иЎЁеӨұиҙҘ');
					this.list = [];
				}
			},
			add() {
				uni.navigateTo({
					url: "/pages/address/add"
				})
			},
			edit(item) {
				const query = [
					`id=${item.id}`,
					`consignee=${encodeURIComponent(item.name || '')}`,
					`phone=${encodeURIComponent(item.phone || '')}`,
					`province=${encodeURIComponent(item.province || 'еӣӣе·қзңҒ')}`,
					`city=${encodeURIComponent(item.city || 'еҚ—е……еёӮ')}`,
					`district=${encodeURIComponent(item.district || '')}`,
					`detailAddress=${encodeURIComponent(item.detailAddress || '')}`,
					`isDefault=${item.isDefault || 0}`,
					`createTime=${encodeURIComponent(item.createTime || '')}`
				].join('&');

				uni.navigateTo({
					url: `/pages/address/add?${query}`
				});
			},
			async setDefaultAddress(item) {
				console.log(item);
				
				const token = uni.getStorageSync('Token') || '';
				if (!token) {
					uni.navigateTo({
						url: '/pages/login/index'
					});
					return;
				}

				try {
					const result = await api.createRequest({
						url: '/house/address/update',
						method: 'put',
						token
					}, {
						id: item.id,
						isDefault: 1,
						consignee: item.name,
						phone: item.phone,
						province: 'еӣӣе·қзңҒ',
						city: 'еҚ—е……еёӮ',
						district: item.district,
						detailAddress: item.detailAddress,
					});

					if (Number(result?.code) === 200) {
						uni.showToast({
							title: result.msg || 'и®ҫзҪ®й»ҳи®Өең°еқҖжҲҗеҠҹ',
							icon: 'success'
						});
						this.fetchAddressList();
					}
				} catch (error) {
					console.error('и®ҫзҪ®й»ҳи®Өең°еқҖеӨұиҙҘпјҡ', error);
				}
			},
			deleteAddress(item) {
				uni.showModal({
					title: 'жҸҗзӨә',
					content: 'зЎ®е®ҡеҲ йҷӨиҜҘең°еқҖеҗ—пјҹ',
					success: async (res) => {
						if (!res.confirm) return;

						const token = uni.getStorageSync('Token') || '';
						if (!token) {
							uni.navigateTo({
								url: '/pages/login/index'
							});
							return;
						}

						try {
							const result = await api.createRequest({
								url: `/house/address/delete/${item.id}`,
								method: 'delete',
								token
							}, {});

							if (Number(result?.code) === 200) {
								uni.showToast({
									title: result.msg || 'еҲ йҷӨжҲҗеҠҹ',
									icon: 'success'
								});
								this.fetchAddressList();
							}
						} catch (error) {
							console.error('еҲ йҷӨең°еқҖеӨұиҙҘпјҡ', error);
						}
					}
				});
			}
		}
	}
</script>

<style>
	page {
		background: #F8F9FA;
	}
</style>

<style lang="scss" scoped>
	.container {
		margin: 20rpx 30rpx;
	}

	.address {
		display: flex;
		align-items: flex-start;
		justify-content: space-between;
		background: #FFFFFF;
		border-radius: 20rpx;
		padding: 32rpx 20rpx;
		margin-bottom: 22rpx;

		.address-info {
			display: flex;
			flex-direction: column;
			padding: 0rpx 40rpx 0rpx 20rpx;

			.address-info-top {
				font-size: 30rpx;
				font-weight: 600;
				color: #333333;

				.tag {
					background: #D5EBD3;
					border-radius: 10rpx;
					font-size: 16rpx;
					color: #40AE36;
					padding: 4rpx 8rpx;
					margin-right: 16rpx;
				}

				.name {
					margin-right: 16rpx;
				}
			}

			.address-info-bottom {
				font-size: 26rpx;
				color: #999999;
				margin-top: 10rpx;
			}
		}

		.address-actions {
			display: flex;
			flex-direction: column;
			align-items: flex-end;
			gap: 20rpx;

			text {
				font-size: 24rpx;
				line-height: 1;
			}

			.action-edit {
				color: #40AE36;
			}

			.action-default {
				color: #2B7AF8;
			}

			.action-default.active {
				color: #40AE36;
			}

			.action-delete {
				color: #FA5151;
			}
		}
	}

	.btn {
		margin-top: 70rpx;
		width: 100%;

		button {
			flex: 1;
			border-radius: 46rpx;
			background: #40AE36;
			color: #FFFFFF;
			font-size: 30rpx;
			padding: 12rpx 0rpx;
		}
	}
</style>
